import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

const ItemCard = ({ item }) => {
  return (
    <motion.div 
      whileHover={{ y: -8, scale: 1.02 }}
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="item-card card"
    >
      <Link to={`/item/${item._id}`} style={{ textDecoration: 'none', color: 'inherit', display: 'flex', flexDirection: 'column', height: '100%' }}>
        <div className="item-image-wrapper">
          <span className={`status-badge status-${item.status}`}>
            {item.status}
          </span>
          {item.imageUrl ? (
            <img src={item.imageUrl} alt={item.title} className="item-image" />
          ) : (
            <div className="no-image">No Image</div>
          )}
        </div>
        <div className="item-info">
          <h3>{item.title}</h3>
          <p>{item.description}</p>
          <div className="tags">
            {item.tags?.slice(0, 3).map((t, i) => (
              <span key={i} className="tag">#{t}</span>
            ))}
            {item.tags?.length > 3 && <span className="tag">+{item.tags.length - 3}</span>}
          </div>
        </div>
      </Link>
    </motion.div>
  );
};

export default ItemCard;

import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

const MatchCard = ({ matchInfo }) => {
  const { item, score, commonTags } = matchInfo;
  if (!item) return null;

  let scoreColor = '#ef4444'; // Red (weak)
  if (score >= 80) scoreColor = '#10b981'; // Green (strong)
  else if (score >= 50) scoreColor = '#f59e0b'; // Yellow (medium)

  return (
    <motion.div 
       whileHover={{ scale: 1.02, x: 5 }}
       initial={{ opacity: 0, x: -10 }}
       animate={{ opacity: 1, x: 0 }}
       className="match-card card"
    >
      <Link to={`/item/${item._id}`} className="match-card-content">
        <div className="match-image">
           {item.imageUrl ? <img src={item.imageUrl} alt={item.title} /> : <div className="match-no-image">📸</div>}
        </div>
        <div className="match-details">
          <div className="match-header">
            <h4>{item.title}</h4>
          </div>

          <div className="score-container mt-2">
            <div className="score-header">
              <span className="score-text" style={{color: scoreColor}}>{score}% Match Score</span>
            </div>
            <div className="progress-bar-bg">
              <motion.div 
                className="progress-bar-fill" 
                initial={{ width: 0 }}
                animate={{ width: `${score}%` }}
                transition={{ duration: 1, ease: "easeOut" }}
                style={{ backgroundColor: scoreColor }}
              />
            </div>
            {matchInfo.explanation && <p className="match-explanation" style={{ fontSize: '0.8rem', color: '#6b7280', marginTop: '0.5rem' }}>ℹ️ {matchInfo.explanation}</p>}
          </div>

          <div className="match-tags mt-2">
            {commonTags?.map((t, i) => <span key={i} className="match-tag" style={{ border: `1px solid ${scoreColor}40`}}>🔥 {t}</span>)}
          </div>
        </div>
      </Link>
    </motion.div>
  );
};

export default MatchCard;

import React, { useState, useEffect, useRef } from 'react';
import { Search } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { getSuggestions } from '../services/api';

const SearchBar = ({ onSearch }) => {
  const [query, setQuery] = useState('');
  const [location, setLocation] = useState('');
  const [date, setDate] = useState('');
  const [category, setCategory] = useState('');
  const [status, setStatus] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const fetchSugg = async () => {
      if(query.trim().length > 1) {
        try {
          const { data } = await getSuggestions(query);
          setSuggestions(data);
          setShowSuggestions(true);
        } catch(e) {}
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    };

    const debounce = setTimeout(fetchSugg, 300);
    return () => clearTimeout(debounce);
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if(dropdownRef.current && !dropdownRef.current.contains(e.target)) setShowSuggestions(false);
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    setShowSuggestions(false);
    onSearch({ query, location, date, category, status });
  };

  const handleSuggestionClick = (sugg) => {
    setQuery(sugg);
    setShowSuggestions(false);
    onSearch({ query: sugg, location, date, category, status });
  };

  return (
    <motion.div 
      ref={dropdownRef}
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.1 }}
      className="search-container-wrapper"
    >
      <form onSubmit={handleSubmit} className="search-bar">
        <input 
          type="text" 
          placeholder="Search items, tags, colors..." 
          value={query} 
          onChange={e => setQuery(e.target.value)}
          onFocus={() => { if(suggestions.length > 0) setShowSuggestions(true); }}
        />
        <input 
          type="text" 
          placeholder="Location..." 
          value={location} 
          onChange={e => setLocation(e.target.value)}
          style={{ borderLeft: '1px solid #eee', paddingLeft: '1rem' }}
        />
        <button 
          type="button" 
          onClick={() => setShowFilters(!showFilters)}
          className="filter-toggle-btn"
          style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '0.5rem', borderLeft: '1px solid #eee' }}
        >
          Filters
        </button>
        <motion.button 
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          type="submit" 
          className="button"
        >
          <Search size={18} /> Search
        </motion.button>
      </form>

      {showFilters && (
        <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="advanced-filters" style={{ display: 'flex', gap: '1rem', marginTop: '1rem', padding: '1rem', background: '#fff', borderRadius: '8px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
          <select value={status} onChange={e => setStatus(e.target.value)} style={{ padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}>
            <option value="">Any Status</option>
            <option value="lost">Lost</option>
            <option value="found">Found</option>
          </select>
          <select value={date} onChange={e => setDate(e.target.value)} style={{ padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}>
            <option value="">Any Time</option>
            <option value="today">Today</option>
            <option value="week">Past Week</option>
            <option value="month">Past Month</option>
          </select>
        </motion.div>
      )}

      <AnimatePresence>
        {showSuggestions && suggestions.length > 0 && (
          <motion.div 
            initial={{ opacity: 0, y: -5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }}
            className="suggestions-dropdown card"
          >
            {suggestions.map((sugg, i) => (
              <div key={i} className="suggestion-item" onClick={() => handleSuggestionClick(sugg)}>
                <Search size={14} style={{marginRight:'0.5rem', opacity:0.5}}/>
                {sugg}
              </div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default SearchBar;

import React, { createContext, useContext, useState, useEffect } from "react";
import axios from "axios";
import toast from "react-hot-toast";

const API_URL = "http://localhost:5000/auth";

export const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchUser = async () => {
      let userInfo = localStorage.getItem("userInfo");
      if (userInfo) {
        userInfo = JSON.parse(userInfo);
        try {
          const res = await axios.get(`${API_URL}/me`, {
            headers: { Authorization: `Bearer ${userInfo.token}` },
          });
          setUser({ ...res.data, token: userInfo.token });
        } catch (error) {
          console.error("Token expired or invalid");
          localStorage.removeItem("userInfo");
        }
      }
      setLoading(false);
    };
    fetchUser();
  }, []);

  const login = async (email, password) => {
    try {
      const res = await axios.post(`${API_URL}/login`, { email, password });
      setUser(res.data);
      localStorage.setItem("userInfo", JSON.stringify(res.data));
      toast.success("Logged in successfully");
      return true;
    } catch (error) {
      toast.error(error.response?.data?.error || "Login failed");
      return false;
    }
  };

  const signup = async (name, email, password) => {
    try {
      const res = await axios.post(`${API_URL}/signup`, { name, email, password });
      setUser(res.data);
      localStorage.setItem("userInfo", JSON.stringify(res.data));
      toast.success("Account created successfully");
      return true;
    } catch (error) {
      toast.error(error.response?.data?.error || "Signup failed");
      return false;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem("userInfo");
    toast.success("Logged out successfully");
  };

  const updateUser = (data) => setUser({ ...user, ...data });

  return (
    <AuthContext.Provider value={{ user, loading, login, signup, logout, updateUser }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { createItem } from '../services/api';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { Upload, X } from 'lucide-react';
import MatchCard from '../components/MatchCard';
import { useAuth } from '../context/AuthContext';
import './Form.css';

const AddItem = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [data, setData] = useState({ title: '', description: '', tags: '', location: '', status: 'lost' });
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [topMatches, setTopMatches] = useState([]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if(!data.title) return toast.error("Title is required!");
    setLoading(true);
    const toastId = toast.loading("Analyzing & Reporting Item...");

    try {
      if (!user) {
        return toast.error("Please log in to report an item");
      }
      const formData = new FormData();
      Object.keys(data).forEach(k => formData.append(k, data[k]));
      formData.append('userId', user._id); 
      if (image) formData.append('image', image);

      const res = await createItem(formData);

      if (res.data.matchCount > 0) {
         toast.success(`Reported! Found ${res.data.matchCount} potential matches.`, { id: toastId });
         setTopMatches(res.data.item.matches.slice(0, 3)); // show top 3
      } else {
         toast.success("Item successfully reported!", { id: toastId });
         setTimeout(() => navigate('/'), 1000);
      }
    } catch (e) {
      toast.error('Failed to report item', { id: toastId });
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="form-wrapper">
      <div className="form-container card">
        <div className="form-header">
           <h2 className="page-title">Report New Entry</h2>
           <p className="subtitle">Our algorithm will instantly scan for matches.</p>
        </div>

        <form onSubmit={handleSubmit} className="custom-form">
          <div className="toggle-group form-input" style={{padding: '0.5rem', display:'flex', gap:'0.5rem'}}>
            <motion.div className={`toggle ${data.status === 'lost' ? 'active-lost' : ''}`} whileTap={{ scale: 0.95 }} onClick={() => setData({...data, status:'lost'})}>
              😞 Lost Something
            </motion.div>
            <motion.div className={`toggle ${data.status === 'found' ? 'active-found' : ''}`} whileTap={{ scale: 0.95 }} onClick={() => setData({...data, status:'found'})}>
              😇 Found Something
            </motion.div>
          </div>

          <input className="form-input" required placeholder="Short Title (e.g. Leather Wallet)" value={data.title} onChange={e => setData({...data, title: e.target.value})} />
          <textarea className="form-input" rows="4" required placeholder="Description (Location, Time, Distinctive Marks)..." value={data.description} onChange={e => setData({...data, description: e.target.value})} />
          <input className="form-input" placeholder="Location where it was lost/found" value={data.location} onChange={e => setData({...data, location: e.target.value})} />
          <input className="form-input" placeholder="Tags (comma separated e.g. wallet, brown, campus)" value={data.tags} onChange={e => setData({...data, tags: e.target.value})} />

          <label className="upload-box form-input">
            <input type="file" accept="image/*" onChange={(e) => {
               if(e.target.files[0]) { setImage(e.target.files[0]); setPreview(URL.createObjectURL(e.target.files[0])); }
            }} style={{display:'none'}} />
            {preview ? (
              <div className="preview-wrap">
                 <img src={preview} alt="Upload preview" className="image-preview" />
                 <span className="upload-change-text">Click to change</span>
              </div>
            ) : (
              <div className="upload-placeholder">
                <Upload size={32} color="var(--primary-color)" style={{marginBottom:'0.5rem'}}/>
                <span>Drag & Drop image here</span>
              </div>
            )}
          </label>

          <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} type="submit" className="btn-primary form-btn" disabled={loading}>
            {loading ? 'Processing...' : 'Submit & Check Matches'}
          </motion.button>
        </form>
      </div>

      <AnimatePresence>
        {topMatches.length > 0 && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="modal-overlay">
            <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="modal-content card match-modal">
               <button className="close-btn" onClick={() => navigate('/')}><X/></button>
               <h2 style={{color:'#a855f7', marginBottom:'0.5rem'}}>🔥 Immediate Matches Found!</h2>
               <p style={{marginBottom:'1.5rem', color:'var(--text-secondary)'}}>Review these items before creating another report.</p>

               <div className="matches-feed" style={{display:'flex', flexDirection:'column', gap:'1rem'}}>
                 {topMatches.map((m, i) => <MatchCard key={i} matchInfo={m}/>)}
               </div>

               <button className="btn-primary" style={{marginTop:'2rem', width:'100%'}} onClick={() => navigate('/')}>Return to Timeline</button>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};
export default AddItem;

import React, { useEffect, useState } from 'react';
import { getItems, searchItems, getTrendingTags, getRecentActivity } from '../services/api';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';
import { ShieldCheck, Zap, Crosshair } from 'lucide-react';
import ItemCard from '../components/ItemCard';
import SearchBar from '../components/SearchBar';
import './Home.css';
import './HomeSidebar.css';

const Home = () => {
  const [items, setItems] = useState([]);
  const [trending, setTrending] = useState([]);
  const [activity, setActivity] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchActive, setSearchActive] = useState(false);

  useEffect(() => {
    fetchInitialData();
    const interval = setInterval(() => {
      // Background poll: doesn't set loading to true
      Promise.all([
        getItems(),
        getTrendingTags(),
        getRecentActivity()
      ]).then(([itemsRes, trendRes, actRes]) => {
        setItems(prev => searchActive ? prev : itemsRes.data);
        setTrending(trendRes.data);
        setActivity(actRes.data);
      }).catch(() => {});
    }, 10000); // 10s poll
    return () => clearInterval(interval);
  }, []);

  const fetchInitialData = async () => {
    try {
      const [itemsRes, trendRes, actRes] = await Promise.all([
        getItems(),
        getTrendingTags(),
        getRecentActivity()
      ]);
      setItems(itemsRes.data);
      setTrending(trendRes.data);
      setActivity(actRes.data);
    } catch (e) {
      toast.error("Failed to load dashboard data");
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async (searchParams) => {
    setLoading(true);
    try {
      // searchParams can be string from trending tags, or object from search bar
      const params = typeof searchParams === 'string' ? { query: searchParams } : searchParams;

      if (!params.query?.trim() && !params.location && !params.status && !params.date) {
        setSearchActive(false);
        const { data } = await getItems();
        setItems(data);
      } else {
        setSearchActive(true);
        const { data } = await searchItems(params);
        setItems(data);
        toast.success(`Found ${data.length} matches!`, { icon: '🔍' });
      }
    } catch (e) {
      toast.error("Search failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }} 
      exit={{ opacity: 0 }}
      className="container home-container"
    >
      <motion.div 
         initial={{ y: -30, opacity: 0 }}
         animate={{ y: 0, opacity: 1 }}
         transition={{ duration: 0.8, ease: "easeOut" }}
      >
        <h1 className="hero-title">
          Find What You Lost. Return What You Found.
        </h1>
        <p className="hero-sub">
          A smart digital lost & found platform
        </p>
      </motion.div>

      <div className="search-container">
        <SearchBar onSearch={handleSearch} />
      </div>

      {/* Trending Tags Section */}
      {trending.length > 0 && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="trending-section">
          <span className="trending-title">Trending Searches:</span>
          {trending.map((tag, i) => (
            <motion.span 
              key={i} 
              whileHover={{ scale: 1.05 }}
              className="tag"
              onClick={() => handleSearch(tag)}
            >
              #{tag}
            </motion.span>
          ))}
        </motion.div>
      )}

      <div className="main">
        <div className="main-feed">
          {loading ? (
             <div className="items-grid">
               {[1,2,3,4].map(n => <div key={n} className="skeleton-card card"></div>)}
             </div>
          ) : (
            <AnimatePresence>
              {items.length === 0 ? (
                <motion.div 
                   initial={{ scale: 0.9, opacity: 0 }} 
                   animate={{ scale: 1, opacity: 1 }}
                   className="empty-state card"
                >
                  <img src="https://cdni.iconscout.com/illustration/premium/thumb/empty-state-2130362-1800926.png" alt="Empty" className="empty-illustration"/>
                  <h3>Looks like nothing here 👀</h3>
                  <p>Try searching something else or browse the recent feed.</p>
                  <button onClick={() => fetchInitialData()} className="button empty-btn">Reload Feed</button>
                </motion.div>
              ) : (
                <motion.div layout className="items-grid">
                  <AnimatePresence>
                    {items.map(item => (
                      <ItemCard key={item._id} item={item} />
                    ))}
                  </AnimatePresence>
                </motion.div>
              )}
            </AnimatePresence>
          )}
        </div>

        {/* Sidebar: Recent Activity & Features */}
        <div className="home-sidebar">
          <div className="card sidebar-widget activity-feed">
            <h3>Live Activity</h3>
            {activity.map((act, i) => (
              <motion.div 
                key={act._id} 
                initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: i * 0.1 }}
                className="activity-item"
              >
                <div className={`activity-dot dot-${act.status}`}></div>
                <div className="activity-text">
                  <p>{act.message}</p>
                  <small>{new Date(act.createdAt).toLocaleTimeString()}</small>
                </div>
              </motion.div>
            ))}
          </div>

          <div className="card sidebar-widget features-widget">
            <h3>Why Back2You?</h3>
            <ul className="features-list">
              <li><Zap className="feature-icon" color="#6366f1"/> <span><b>Smart Matching:</b> AI algorithm scores similarities instantly.</span></li>
              <li><ShieldCheck className="feature-icon" color="#10b981"/> <span><b>Secure Claims:</b> Proof-based claiming protects belongings.</span></li>
              <li><Crosshair className="feature-icon" color="#3b82f6"/> <span><b>Fuzzy Search:</b> Find it faster using tags and colors.</span></li>
            </ul>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default Home;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getItemById, createClaim } from '../services/api';
import MatchCard from '../components/MatchCard';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { ShieldCheck, Tag, Box, ArrowLeft, Bookmark, MapPin } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './ItemDetail.css';

const ItemDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [item, setItem] = useState(null);
  const [claimModal, setClaimModal] = useState(false);
  const [claimText, setClaimText] = useState('');
  const [loading, setLoading] = useState(true);
  const [claiming, setClaiming] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [claims, setClaims] = useState([]);
  const [chatMessage, setChatMessage] = useState('');

  useEffect(() => {
    getItemById(id)
      .then(({ data }) => setItem(data))
      .catch(() => toast.error("Failed to fetch item details"))
      .finally(() => setLoading(false));

    if (user && user.savedItems) {
      if (typeof user.savedItems[0] === 'object') {
        setIsSaved(user.savedItems.some(item => item._id === id));
      } else {
        setIsSaved(user.savedItems.includes(id));
      }
    }

    if (user) {
      axios.get(`http://localhost:5000/claims/item/${id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      }).then(res => setClaims(res.data)).catch(err => console.error(err));
    }
  }, [id, user]);

  const handleUpdateClaim = async (claimId, status) => {
    try {
      await axios.patch(`http://localhost:5000/claims/${claimId}`, { status }, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      setClaims(claims.map(c => c._id === claimId ? { ...c, status } : c));
      toast.success(`Claim marked as ${status}`);
    } catch (e) {
      toast.error('Failed to update claim');
    }
  };

  const handleSendMessage = async (claimId) => {
    if (!chatMessage.trim()) return;
    try {
      const { data } = await axios.post(`http://localhost:5000/claims/${claimId}/message`, {
        text: chatMessage,
        senderId: user._id
      }, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      setClaims(claims.map(c => c._id === claimId ? data : c));
      setChatMessage('');
    } catch (e) {
      toast.error('Failed to send message');
    }
  };

  const toggleSave = async () => {
    if (!user) return toast.error("Please log in to save items");
    try {
      const res = await axios.post(`http://localhost:5000/users/save/${id}`, {}, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      setIsSaved(res.data.savedItems.includes(id));
      toast.success(isSaved ? "Item removed from saved" : "Item saved!");
    } catch(e) {
      toast.error("Failed to save item");
    }
  };

  const submitClaim = async () => {
    if(!user) return toast.error("Please log in to claim items");
    if(!claimText.trim()) return toast.error("Proof is required to claim!");
    setClaiming(true);
    const toastId = toast.loading("Submitting Security Claim...");
    try {
      await createClaim({ itemId: item._id, userId: user._id, proofMessage: claimText });
      toast.success("Claim Request Submitted! Sent for review.", { id: toastId });
      setClaimModal(false);
      setClaimText('');
    } catch(e) {
      toast.error("Failed submitting claim", { id: toastId });
    } finally {
      setClaiming(false);
    }
  }

  if (loading) return (
    <div className="skeleton-detail">
      <div className="skeleton-card skeleton-img card"></div>
      <div className="skeleton-card skeleton-info card"></div>
    </div>
  );

  if (!item) return <div className="empty-state card"><h2>Entry Corrupted</h2></div>;

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="detail-container">
      <button onClick={() => navigate(-1)} className="back-btn button">
        <ArrowLeft size={18} /> Back
      </button>

      <div className="detail-grid">
        <motion.div initial={{ x: -20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="detail-img-box card">
          <span className={`status-badge-lg status-${item.status}`}>
            {item.status === 'lost' ? 'Reported Lost 🔴' : 'Reported Found 🟢'}
          </span>
          {item.imageUrl ? <img src={item.imageUrl} alt={item.title} /> : <div className="detail-no-img"><Box size={64}/></div>}
        </motion.div>

        <motion.div initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="detail-info-box card">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <h1>{item.title}</h1>
            <button 
              onClick={toggleSave}
              className={`button icon-button ${isSaved ? 'saved' : ''}`}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: isSaved ? '#3b82f6' : '#9ca3af' }}
            >
              <Bookmark size={24} fill={isSaved ? '#3b82f6' : 'none'} />
            </button>
          </div>
          <div className="meta-info">Reported by {item.userId?.name || 'Anonymous'} • {new Date(item.createdAt).toLocaleDateString()}</div>
          {item.location && <div className="meta-info location-info mt-2" style={{ display: 'flex', alignItems: 'center', gap: '5px', color: '#6b7280' }}><MapPin size={16}/> {item.location}</div>}

          <div className="desc-section">
            <h3>Description</h3>
            <p>{item.description}</p>
          </div>

          <div className="tags-section">
             <h3>Associated Tags</h3>
             <div className="tags-list">
               {item.tags?.map((t, i) => <span key={i} className="chip"><Tag size={12}/> {t}</span>)}
             </div>
          </div>

          {(!user || user._id !== item.userId?._id) && !claims.some(c => c.userId?._id === user?._id) && (
            <motion.button 
               whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.95 }}
               className="btn-primary claim-trigger mt-4"
               onClick={() => setClaimModal(true)}
            >
               <ShieldCheck size={20}/> Ensure Claim Ownership
            </motion.button>
          )}
        </motion.div>
      </div>

      {user && (
        <div className="claims-section card mt-4" style={{ padding: '2rem' }}>
          <h2>Claims & Chat</h2>
          {claims.length === 0 ? (
            <p style={{ color: '#6b7280' }}>No claims active for this item.</p>
          ) : (
            claims.filter(c => user._id === item.userId?._id || user._id === c.userId?._id).map((claim, idx) => (
              <div key={idx} style={{ border: '1px solid #e5e7eb', borderRadius: '8px', padding: '1rem', marginTop: '1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem', borderBottom: '1px solid #eee', paddingBottom: '0.5rem' }}>
                  <div>
                    <h4 style={{ margin: 0 }}>Claim by {claim.userId?.name || 'Unknown'}</h4>
                    <span style={{ fontSize: '0.85rem', color: '#6b7280' }}>{new Date(claim.createdAt).toLocaleString()}</span>
                    <p style={{ fontSize: '0.9rem', marginTop: '0.5rem', fontStyle: 'italic' }}>"{claim.proofMessage}"</p>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <span className={`status-badge ${claim.status}`} style={{ display: 'inline-block', marginBottom: '0.5rem' }}>Status: {claim.status.toUpperCase()}</span>

                    {user._id === item.userId?._id && claim.status === 'requested' && (
                      <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                        <button onClick={() => handleUpdateClaim(claim._id, 'approved')} style={{ background: '#10b981', color: '#fff', border: 'none', borderRadius: '4px', padding: '0.3rem 0.6rem', cursor: 'pointer' }}>Approve</button>
                        <button onClick={() => handleUpdateClaim(claim._id, 'rejected')} style={{ background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', padding: '0.3rem 0.6rem', cursor: 'pointer' }}>Reject</button>
                      </div>
                    )}
                    {user._id === item.userId?._id && claim.status === 'approved' && (
                      <button onClick={() => handleUpdateClaim(claim._id, 'completed')} style={{ background: '#3b82f6', color: '#fff', border: 'none', borderRadius: '4px', padding: '0.3rem 0.6rem', cursor: 'pointer' }}>Mark Completed</button>
                    )}
                  </div>
                </div>

                {['approved', 'requested', 'completed'].includes(claim.status) && (
                  <div className="chat-box" style={{ background: '#f9fafb', borderRadius: '8px', padding: '1rem' }}>
                    <div style={{ maxHeight: '200px', overflowY: 'auto', marginBottom: '1rem' }}>
                      {claim.messages && claim.messages.map((msg, i) => (
                        <div key={i} style={{ marginBottom: '0.5rem', textAlign: msg.sender?._id === user._id ? 'right' : 'left' }}>
                          <span style={{ fontSize: '0.8rem', fontWeight: 'bold' }}>{msg.sender?.name}:</span>
                          <span style={{ display: 'inline-block', background: msg.sender?._id === user._id ? '#e0f2fe' : '#fff', padding: '0.4rem 0.8rem', borderRadius: '16px', marginLeft: '0.5rem', boxShadow: '0 1px 2px rgba(0,0,0,0.05)' }}>{msg.text}</span>
                        </div>
                      ))}
                    </div>
                    {claim.status !== 'completed' && (
                      <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <input type="text" value={chatMessage} onChange={e => setChatMessage(e.target.value)} placeholder="Type a message..." style={{ flex: 1, padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }} />
                        <button onClick={() => handleSendMessage(claim._id)} style={{ background: '#3b82f6', color: '#fff', border: 'none', borderRadius: '4px', padding: '0.5rem 1rem', cursor: 'pointer' }}>Send</button>
                      </div>
                    )}

                    {claim.status === 'completed' && user._id === claim.userId?._id && (
                      <div className="feedback-box mt-4" style={{ borderTop: '1px solid #e5e7eb', paddingTop: '1rem' }}>
                        <h4 style={{ margin: '0 0 0.5rem 0' }}>Rate your experience!</h4>
                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                          <input type="number" min="1" max="5" placeholder="Rating (1-5)" id="rating-input" style={{ width: '100px', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}/>
                          <input type="text" placeholder="Leave a comment (optional)" id="comment-input" style={{ flex: 1, padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}/>
                          <button onClick={async () => {
                            const r = document.getElementById('rating-input').value;
                            const c = document.getElementById('comment-input').value;
                            if(!r) return toast.error("Rating is required");
                            try {
                              await axios.post('http://localhost:5000/feedback', { rating: r, comment: c, claimId: claim._id }, { headers: { Authorization: `Bearer ${user.token}` } });
                              toast.success("Thanks for your feedback!");
                            } catch(e) { toast.error("Failed to submit feedback"); }
                          }} style={{ background: '#f59e0b', color: '#fff', border: 'none', borderRadius: '4px', padding: '0.5rem 1rem', cursor: 'pointer' }}>Submit Feedback</button>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      )}

      {item.matches?.length > 0 && (
        <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className="advanced-matches-section card">
          <div className="match-header-title">
            <h2>🔥 High Probability Matches ({item.matches.length})</h2>
            <p className="subtitle">Our algorithm found the following similar reports.</p>
          </div>
          <div className="match-cards-grid">
            {item.matches.map(m => <MatchCard key={m.item?._id || m._id} matchInfo={m} />)}
          </div>
        </motion.div>
      )}

      {/* Modern Modal UX */}
      <AnimatePresence>
        {claimModal && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="modal-overlay"
            onClick={() => setClaimModal(false)}
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0 }}
              className="modal-content card"
              onClick={e => e.stopPropagation()}
            >
              <h2>Secure Claim Initialization</h2>
              <p>For security, please provide precise details proving this item belongs to you (e.g. secret pocket, damage, IMEI).</p>

              <textarea 
                className="form-input mt-4" rows="4" 
                placeholder="I know this is mine because..."
                value={claimText} onChange={e => setClaimText(e.target.value)}
              />
              <div className="modal-actions mt-4">
                 <button className="button cancel-btn" onClick={() => setClaimModal(false)}>Cancel</button>
                 <button className="btn-primary submit-btn" disabled={claiming} onClick={submitClaim}>
                   {claiming ? 'Processing...' : 'Submit Evidence'}
                 </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default ItemDetail;
